INSERT INTO activities (title, category, location, organizer, description, content, start_time, end_time, registration_deadline, max_participants, current_participants, cover_image, branch_id, created_by, created_at, updated_at) VALUES
('红芯软炬 | 党建引领促发展 科技赋能谱新篇——教师荆心赴陕西省团校开展人工智能专题培训交流会', 'training', '陕西省团校', '计算机科学与工程学院教师第三党支部', '深入贯彻习近平总书记关于发展新质生产力和人工智能创新发展的重要论述，开展人工智能专题培训交流', '<h2>活动详情</h2><p>为深入贯彻习近平总书记关于发展新质生产力和人工智能创新发展的重要论述，近日，计算机科学与工程学院教师第三党支部选派优秀党员教师荆心，赴陕西省团校为中国移动陕西公司的青年技术骨干开展"人工智能赋能通讯行业创新应用——以DeepSeek为例"专题培训。</p><p>培训伊始，荆心老师带领学员认真学习领会习近平总书记关于人工智能发展的重要论述，强调人工智能是引领科技革命和产业变革的战略技术，通讯行业青年骨干要主动拥抱智能时代，投身创新实践。</p>', '2025-12-07 09:00:00', '2025-12-07 16:00:00', '2025-12-05 23:59:59', 50, 45, 'https://picsum.photos/id/237/800/450', 1, 1, NOW(), NOW()),
